detaileddescription.para:
Usage: uint8_tbuf[32];
size_tpos=0;

//Pack(big-endian)
syn_pack_u8(buf,&pos,0x42);
syn_pack_u16(buf,&pos,0x1234);
syn_pack_i32(buf,&pos,-12345);
syn_pack_bytes(buf,&pos,payload,4);

//Unpack
pos=0;
uint8_ta=syn_unpack_u8(buf,&pos);
uint16_tb=syn_unpack_u16(buf,&pos);
int32_tc=syn_unpack_i32(buf,&pos);
